            val slopeMap = mutableMapOf<String, MutableList<Pair<Int, Int>>>()
            for (k in 0 until n) {
                if (k == i || k == j) continue
                val (x1, y1) = points[i]
                val (x2, y2) = points[j]
                val (x3, y3) = points[k]

                // Calculate the slope of line (i,j) and (i,k)
                val dx1 = x2 - x1
                val dy1 = y2 - y1
                val dx2 = x3 - x1
                val dy2 = y3 - y1

                // Cross product to check if collinear (to avoid counting as parallel)
                if (dx1 * dy2 == dx2 * dy1) continue

                // Calculate slope as reduced fraction to avoid floating point precision issues
                val g1 = gcd(dx1, dy1)
                val g2 = gcd(dx2, dy2)
                val slope1 = "${dx1 / g1}/${dy1 / g1}"
                val slope2 = "${dx2 / g2}/${dy2 / g2}"

