                }
            }
            for ((_, lines) in slopeMap) {
                if (lines.size >= 2) {
                    // The number of ways to choose 2 lines from the lines list
                    val m = lines.size
                    count += m * (m - 1) / 2
                }
            }
        }
    }

    // Each trapezoid is counted twice (once for each pair of parallel sides)
    return count / 2
}

